   554→/*NUMPY_API
   555→ * Round
   556→ */
   557→NPY_NO_EXPORT PyObject *
   558→PyArray_Round(PyArrayObject *a, int decimals, PyArrayObject *out)
   559→{
   560→    PyObject *f, *ret = NULL, *tmp, *op1, *op2;
   561→    int ret_int=0;
   562→    PyArray_Descr *my_descr;
   563→    if (out && (PyArray_SIZE(out) != PyArray_SIZE(a))) {
   564→        PyErr_SetString(PyExc_ValueError,
   565→                        "invalid output shape");
   566→        return NULL;
   567→    }
   568→    if (PyArray_ISCOMPLEX(a)) {
   569→        PyObject *part;
   570→        PyObject *round_part;
   571→        PyObject *arr;
   572→        int res;
   573→
   574→        if (out) {
   575→            arr = (PyObject *)out;
   576→            Py_INCREF(arr);
   577→        }
   578→        else {
   579→            arr = PyArray_NewCopy(a, NPY_KEEPORDER);
   580→            if (arr == NULL) {
   581→                return NULL;
   582→            }
   583→        }
   584→
   585→        /* arr.real = a.real.round(decimals) */
   586→        part = PyObject_GetAttrString((PyObject *)a, "real");
   587→        if (part == NULL) {
   588→            Py_DECREF(arr);
   589→            return NULL;
   590→        }
   591→        part = PyArray_EnsureAnyArray(part);
   592→        round_part = PyArray_Round((PyArrayObject *)part,
   593→                                   decimals, NULL);
   594→        Py_DECREF(part);
   595→        if (round_part == NULL) {
   596→            Py_DECREF(arr);
   597→            return NULL;
   598→        }
   599→        res = PyObject_SetAttrString(arr, "real", round_part);
   600→        Py_DECREF(round_part);
   601→        if (res < 0) {
   602→            Py_DECREF(arr);
   603→            return NULL;
   604→        }
   605→
   606→        /* arr.imag = a.imag.round(decimals) */
   607→        part = PyObject_GetAttrString((PyObject *)a, "imag");
   608→        if (part == NULL) {
   609→            Py_DECREF(arr);
   610→            return NULL;
   611→        }
   612→        part = PyArray_EnsureAnyArray(part);
   613→        round_part = PyArray_Round((PyArrayObject *)part,
   614→                                   decimals, NULL);
   615→        Py_DECREF(part);
   616→        if (round_part == NULL) {
   617→            Py_DECREF(arr);
   618→            return NULL;
   619→        }
   620→        res = PyObject_SetAttrString(arr, "imag", round_part);
   621→        Py_DECREF(round_part);
   622→        if (res < 0) {
   623→            Py_DECREF(arr);
   624→            return NULL;
   625→        }
   626→        return arr;
   627→    }
   628→    /* do the most common case first */
   629→    if (decimals >= 0) {
   630→        if (PyArray_ISINTEGER(a)) {
   631→            if (out) {
   632→                if (PyArray_AssignArray(out, a,
   633→                            NULL, NPY_DEFAULT_ASSIGN_CASTING) < 0) {
   634→                    return NULL;
   635→                }
   636→                Py_INCREF(out);
   637→                return (PyObject *)out;
   638→            }
   639→            else {
   640→                return PyArray_NewCopy(a, NPY_KEEPORDER);
   641→            }
   642→        }
   643→        if (decimals == 0) {
   644→            if (out) {
   645→                return PyObject_CallFunction(n_ops.rint, "OO", a, out);
   646→            }
   647→            return PyObject_CallFunction(n_ops.rint, "O", a);
   648→        }
   649→        op1 = n_ops.multiply;
   650→        op2 = n_ops.true_divide;
   651→    }
   652→    else {
   653→        op1 = n_ops.true_divide;
   654→        op2 = n_ops.multiply;
   655→        if (decimals == INT_MIN) {
   656→            // not technically correct but it doesn't matter because no one in
   657→            // this millenium is using floating point numbers with enough
   658→            // accuracy for this to matter
   659→            decimals = INT_MAX;
   660→        }
   661→        else {
   662→            decimals = -decimals;
   663→        }
   664→    }
   665→    if (!out) {
   666→        if (PyArray_ISINTEGER(a)) {
   667→            ret_int = 1;
   668→            my_descr = PyArray_DescrFromType(NPY_DOUBLE);
   669→        }
   670→        else {
   671→            Py_INCREF(PyArray_DESCR(a));
   672→            my_descr = PyArray_DESCR(a);
   673→        }
   674→        out = (PyArrayObject *)PyArray_Empty(PyArray_NDIM(a), PyArray_DIMS(a),
   675→                                             my_descr,
   676→                                             PyArray_ISFORTRAN(a));
   677→        if (out == NULL) {
   678→            return NULL;
   679→        }
   680→    }
   681→    else {
   682→        Py_INCREF(out);
   683→    }
   684→    f = PyFloat_FromDouble(power_of_ten(decimals));
   685→    if (f == NULL) {
   686→        return NULL;
   687→    }
   688→    ret = PyObject_CallFunction(op1, "OOO", a, f, out);
   689→    if (ret == NULL) {
   690→        goto finish;
   691→    }
   692→    tmp = PyObject_CallFunction(n_ops.rint, "OO", ret, ret);
   693→    if (tmp == NULL) {
   694→        Py_DECREF(ret);
   695→        ret = NULL;
   696→        goto finish;
   697→    }
   698→    Py_DECREF(tmp);
   699→    tmp = PyObject_CallFunction(op2, "OOO", ret, f, ret);
   700→    if (tmp == NULL) {
   701→        Py_DECREF(ret);
   702→        ret = NULL;
   703→        goto finish;
   704→    }
   705→    Py_DECREF(tmp);
   706→
   707→ finish:
   708→    Py_DECREF(f);
   709→    Py_DECREF(out);
   710→    if (ret_int && ret != NULL) {
   711→        Py_INCREF(PyArray_DESCR(a));
   712→        tmp = PyArray_CastToType((PyArrayObject *)ret,
   713→                                 PyArray_DESCR(a), PyArray_ISFORTRAN(a));
   714→        Py_DECREF(ret);
   715→        return tmp;
   716→    }
   717→    return ret;
   718→}
