   796→NPY_NO_EXPORT PyObject *
   797→PyArray_Clip(PyArrayObject *self, PyObject *min, PyObject *max, PyArrayObject *out)
   798→{
   799→    /* Treat None the same as NULL */
   800→    if (min == Py_None) {
   801→        min = NULL;
   802→    }
   803→    if (max == Py_None) {
   804→        max = NULL;
   805→    }
   806→
   807→    if ((max == NULL) && (min == NULL)) {
   808→        PyErr_SetString(PyExc_ValueError,
   809→                        "array_clip: must set either max or min");
   810→        return NULL;
   811→    }
   812→
   813→    if (min == NULL) {
   814→        return PyObject_CallFunctionObjArgs(n_ops.minimum, self, max, out, NULL);
   815→    }
   816→    else if (max == NULL) {
   817→        return PyObject_CallFunctionObjArgs(n_ops.maximum, self, min, out, NULL);
   818→    }
   819→    else {
   820→        return PyObject_CallFunctionObjArgs(n_ops.clip, self, min, max, out, NULL);
   821→    }
