              NPY_ITER_ALIGNED |
              NPY_ITER_ALLOCATE |
              NPY_ITER_NO_SUBTYPE;
op_flags[1] = NPY_ITER_READONLY |
              NPY_ITER_ALIGNED |
              NPY_ITER_NO_BROADCAST;

