/* Optimized summation for float arrays using vectorized loops
 * with improved cache locality for better performance
 */
static PyObject *
_PyArray_Sum_Optimized(PyArrayObject *self, int axis, int rtype, PyArrayObject *out)
{
    /* Fast path for float arrays - uses vectorized operations
     * with improved cache efficiency */
    PyArray_Descr *descr = PyArray_DESCR(self);
    int ndim = PyArray_NDIM(self);
    npy_intp size = PyArray_SIZE(self);

    /* Only apply optimization for float types on large arrays */
    if (size < 1000) {
        return NULL;  /* Fall back to generic path for small arrays */
    }

    if ((descr->type_num != NPY_FLOAT64 && descr->type_num != NPY_FLOAT32)) {
        return NULL;  /* Fall back for non-float types */
    }

    /* Check if this is a total reduction (summing all elements) */
    /* When axis=-1 is passed by user or axis=None is converted */
    if (!(axis == -1 || axis == NPY_RAVEL_AXIS)) {
        /* Check if axis has been normalized by caller */
        int check_axis = axis;
        if (check_axis < 0) {
            check_axis += ndim;
        }
        if (check_axis >= 0 && check_axis < ndim) {
            /* This is a reduction along one axis, not all elements */
            return NULL;
        }
    }

    /* Skip optimization if there's an output array (different code path) */
    if (out != NULL) {
        return NULL;
    }

    /* Skip if a different rtype is requested - fall back to generic path */
    if (rtype != descr->type_num && rtype != -1 && rtype != NPY_NOTYPE) {
        return NULL;
    }

    char *data = PyArray_DATA(self);

    if (descr->type_num == NPY_FLOAT64) {
        double sum = 0.0;
        double *ptr = (double *)data;
        npy_intp n = size;

        /* Unroll loop by 8 for better CPU pipelining and cache efficiency
         * This reduces the number of branches and improves instruction-level parallelism
         */
        npy_intp i;
        for (i = 0; i + 7 < n; i += 8) {
            sum += ptr[i] + ptr[i+1] + ptr[i+2] + ptr[i+3] +
                   ptr[i+4] + ptr[i+5] + ptr[i+6] + ptr[i+7];
        }
        /* Handle remaining elements */
        for (; i < n; i++) {
            sum += ptr[i];
        }

        return PyFloat_FromDouble(sum);
    }
    else if (descr->type_num == NPY_FLOAT32) {
        double sum = 0.0;  /* Use double accumulator for better precision */
        float *ptr = (float *)data;
        npy_intp n = size;

        /* Unroll loop by 8 for better CPU pipelining and cache efficiency */
        npy_intp i;
        for (i = 0; i + 7 < n; i += 8) {
            sum += ptr[i] + ptr[i+1] + ptr[i+2] + ptr[i+3] +
                   ptr[i+4] + ptr[i+5] + ptr[i+6] + ptr[i+7];
        }
        /* Handle remaining elements */
        for (; i < n; i++) {
            sum += ptr[i];
        }

        return PyFloat_FromDouble(sum);
    }

    return NULL;  /* Fall back to generic path */
}

/*NUMPY_API
 *Sum
 */
NPY_NO_EXPORT PyObject *
PyArray_Sum(PyArrayObject *self, int axis, int rtype, PyArrayObject *out)
{
    PyObject *arr, *ret;

    /* Try optimized fast path first for float arrays */
    ret = _PyArray_Sum_Optimized(self, axis, rtype, out);
    if (ret != NULL) {
        return ret;
    }
    if (PyErr_Occurred()) {
        return NULL;
    }

    /* Fall back to generic reduce for other cases */
    arr = PyArray_CheckAxis(self, &axis, 0);
    if (arr == NULL) {
        return NULL;
    }
    ret = PyArray_GenericReduceFunction((PyArrayObject *)arr, n_ops.add, axis,
                                        rtype, out);
    Py_DECREF(arr);
    return ret;
}

