/* Optimized summation for float arrays using vectorized loops
 * with improved cache locality for better performance
 */
static PyObject *
_PyArray_Sum_Optimized(PyArrayObject *self, int axis, int rtype, PyArrayObject *out)
{
    /* Fast path for float arrays - uses vectorized operations
     * with improved cache efficiency */
    PyArray_Descr *descr = PyArray_DESCR(self);
    int ndim = PyArray_NDIM(self);
    npy_intp size = PyArray_SIZE(self);

    /* Only apply optimization for float types on large arrays */
    if (size < 1000) {
        return NULL;  /* Fall back to generic path for small arrays */
    }

    if ((descr->type_num != NPY_FLOAT64 && descr->type_num != NPY_FLOAT32)) {
        return NULL;  /* Fall back for non-float types */
    }

